classDiagram(name = "Parking Garage") {
    val spaceType = enumOf(name = "ParkingSpaceType") {
        literal(name = "REGULAR")
        literal(name = "DISABLED")
        literal(name = "ELECTRIC")
    }

    val garage = classOf(name = "ParkingGarage") {
        attribute(name = "id", type = "UUID", isReadOnly = true)
        attribute(name = "name", type = "String")
    }

    val level = classOf(name = "Level") {
        attribute(name = "levelNumber", type = "Int")
    }

    val space = classOf(name = "ParkingSpace") {
        attribute(name = "spaceNumber", type = "String")
        attribute(name = "type", type = spaceType)
    }

    val ticket = classOf(name = "Ticket") {
        attribute(name = "id", type = "UUID", isReadOnly = true)
        attribute(name = "entryTime", type = "DateTime")
    }

    association(source = garage, target = level) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "levels" }
    }

    association(source = level, target = space) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "spaces" }
    }

    association(source = space, target = ticket) {
        source { multiplicity(spec = "0..1"); role = "space" }
        target { multiplicity(spec = "0..1"); role = "ticket" }
    }
}

