classDiagram(name = "Bank Account Domain") {
    val customer = classOf(name = "Customer") {
        attribute(name = "id", type = "UUID")
        attribute(name = "name", type = "String")
    }

    val interestContract = interfaceOf(name = "InterestContract") {
        operation(name = "calculateInterest") { returns(typeName = "BigDecimal") }
    }

    val transactionType = enumOf(name = "TransactionType") {
        literal(name = "DEPOSIT")
        literal(name = "WITHDRAWAL")
        literal(name = "TRANSFER")
    }

    val account = classOf(name = "Account") {
        isAbstract = true
        attribute(name = "iban", type = "String", isReadOnly = true)
        attribute(name = "balance", type = "BigDecimal")
    }

    val checkingAccount = classOf(name = "CheckingAccount") {
        attribute(name = "overdraftLimit", type = "BigDecimal")
        extends(general = account)
    }

    val savingsAccount = classOf(name = "SavingsAccount") {
        attribute(name = "interestRate", type = "BigDecimal")
        implements(iface = interestContract)
        extends(general = account)
    }

    val transaction = classOf(name = "Transaction") {
        attribute(name = "amount", type = "BigDecimal")
        attribute(name = "timestamp", type = "DateTime")
        attribute(name = "type", type = transactionType)
    }

    association(source = customer, target = account) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "accounts" }
    }

    association(source = account, target = transaction) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "transactions" }
    }
}

classDiagram(name = "Online Shop") {
