        attribute(name = "placedAt", type = "LocalDateTime")
    }

    association(source = customer, target = address) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "1..*"); role = "addresses" }
    }

    association(source = customer, target = cart) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..1"); role = "activeCart" }
    }

    association(source = cart, target = lineItem) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "lineItems" }
    }

    association(source = lineItem, target = product) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "product" }
    }

    association(source = customer, target = order) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "orders" }
    }

    dependency(client = cart, supplier = order, name = "createsOnCheckout")
}

classDiagram(name = "School Domain") {
    val school = classOf(name = "School") {
        attribute(name = "name", type = "String")
    }

    val schoolClass = classOf(name = "SchoolClass") {
        attribute(name = "name", type = "String")
    }

    val teacher = classOf(name = "Teacher") {
        attribute(name = "name", type = "String")
    }

    val student = classOf(name = "Student") {
        attribute(name = "name", type = "String")
    }

    val subject = classOf(name = "Subject") {
        attribute(name = "name", type = "String")
    }

    val lesson = classOf(name = "Lesson") {
        attribute(name = "timeSlot", type = "String")
    }

    val reportCard = classOf(name = "ReportCard") {
        attribute(name = "issueDate", type = "Date")
        attribute(name = "grades", type = "String")
    }

    // A class cannot exist without the school -> composition
    association(source = school, target = schoolClass) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "classes" }
    }

    // Each class has exactly one homeroom teacher; teacher can lead multiple classes
    association(source = teacher, target = schoolClass) {
        source { multiplicity(spec = "1"); role = "homeroomTeacher" }
        target { multiplicity(spec = "0..*"); role = "classes" }
    }

    // Any number of students belong to a class
    association(source = schoolClass, target = student) {
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "students" }
    }

    // Lesson brings together a subject, a teacher, and a class
    association(source = lesson, target = subject) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "subject" }
    }

    association(source = lesson, target = teacher) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "teacher" }
    }

    association(source = lesson, target = schoolClass) {
        source { multiplicity(spec = "0..*") }
        target { multiplicity(spec = "1"); role = "class" }
    }

    // Report cards are inseparably linked to the student -> composition
    association(source = student, target = reportCard) {
        aggregation = AggregationKind.COMPOSITE
        source { multiplicity(spec = "1") }
        target { multiplicity(spec = "0..*"); role = "reportCards" }
    }
}

