sequenceDiagram(name = "Product Search") {
    val buyer = lifeline(name = "Buyer") { isActor = true }
    val shop = lifeline(name = "WebShop")
    val searchService = lifeline(name = "SearchService")
    val catalog = lifeline(name = "ProductCatalog")

    message(from = buyer, to = shop, label = "enterSearchTerm()")
    message(from = shop, to = searchService, label = "search(term)")
    message(from = searchService, to = catalog, label = "findMatchingProducts(term)")
    reply(from = catalog, to = searchService, label = "products")
    reply(from = searchService, to = shop, label = "results")

    opt(guard = "[results found]") {
        message(from = shop, to = catalog, label = "loadProductImages(results)")
        reply(from = catalog, to = shop, label = "images")
    }

    reply(from = shop, to = buyer, label = "resultsPage")
}

sequenceDiagram(name = "Checkout Process") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val shop = lifeline(name = "Shop")
    val checkoutService = lifeline(name = "CheckoutService")
    val paymentGateway = lifeline(name = "PaymentGateway")
    val db = lifeline(name = "Database")

    message(from = customer, to = shop, label = "startCheckout()")
    message(from = shop, to = checkoutService, label = "processCheckout()")
    message(from = checkoutService, to = paymentGateway, label = "verifyPaymentDetails()")
    reply(from = paymentGateway, to = checkoutService, label = "verificationResult")

    alt {
        branch(guard = "[valid]") {
            message(from = checkoutService, to = db, label = "saveOrder()")
            reply(from = db, to = checkoutService, label = "orderSaved")
            message(from = checkoutService, to = paymentGateway, label = "processPayment()")
            reply(from = paymentGateway, to = checkoutService, label = "paymentConfirmed")
            reply(from = checkoutService, to = shop, label = "success")
        }
        branch(guard = "[invalid]") {
            reply(from = checkoutService, to = shop, label = "error: invalid payment details")
        }
    }

    reply(from = shop, to = customer, label = "checkout result")
}

sequenceDiagram(name = "API Rate Limiting") {
    val client = lifeline(name = "Client") { isActor = true }
    val gateway = lifeline(name = "APIGateway")
    val limiter = lifeline(name = "RateLimiter")
    val backend = lifeline(name = "BackendService")

    loop(guard = "[retries < 3]") {
        message(from = client, to = gateway, label = "requestData()")
        message(from = gateway, to = limiter, label = "checkQuota(client)")

        alt {
            branch(guard = "[quota available]") {
                reply(from = limiter, to = gateway, label = "quotaOk")
                message(from = gateway, to = backend, label = "forwardRequest()")
                reply(from = backend, to = gateway, label = "data")
                reply(from = gateway, to = client, label = "data")
            }
            branch(guard = "[quota exhausted]") {
                reply(from = limiter, to = gateway, label = "quotaExceeded")
                reply(from = gateway, to = client, label = "429 Too Many Requests")
                message(from = client, to = client, label = "wait(backoffPeriod)")
            }
        }
    }
}

sequenceDiagram(name = "Password Reset") {
    val user     = lifeline(name = "User") { isActor = true }
    val portal   = lifeline(name = "WebPortal")
    val authSvc  = lifeline(name = "AuthService")
    val userDb   = lifeline(name = "UserDB")
    val mailSvc  = lifeline(name = "EmailService")

    message(from = user, to = portal, label = "requestPasswordReset(email)")
    message(from = portal, to = authSvc, label = "resetPassword(email)")
    message(from = authSvc, to = userDb, label = "findUserByEmail(email)")
    reply(from = userDb, to = authSvc, label = "user | none")

    alt {
        branch(guard = "[user exists]") {
            message(from = authSvc, to = authSvc, label = "generateResetToken()")
            message(from = authSvc, to = userDb, label = "storeResetToken(token)")
            reply(from = userDb, to = authSvc, label = "ok")

            // Fire-and-forget: das Senden der E-Mail wird angestoßen, ohne auf Abschluss zu warten
            asyncMessage(from = authSvc, to = mailSvc, label = "sendResetEmail(email, token)")

            reply(from = authSvc, to = portal, label = "200 OK (generic success)")
        }
        branch(guard = "[user unknown]") {
            reply(from = authSvc, to = portal, label = "200 OK (generic success)")
        }
    }

    reply(from = portal, to = user, label = "\"If this email exists, a reset link was sent.\"")
}

sequenceDiagram(name = "Order Request — JWT Validation") {
    val client       = lifeline(name = "Client") { isActor = true }
    val gateway      = lifeline(name = "APIGateway")
    val tokenCache   = lifeline(name = "TokenCache")
    val authService  = lifeline(name = "AuthService")
    val orderService = lifeline(name = "OrderService")

    message(from = client, to = gateway, label = "GET /orders (JWT)")
    message(from = gateway, to = tokenCache, label = "lookup(token)")

    alt {
        branch(guard = "[cache miss]") {
            reply(from = tokenCache, to = gateway, label = "not found")
            message(from = gateway, to = authService, label = "verify(token)")
            reply(from = authService, to = gateway, label = "validationResult")
            message(from = gateway, to = tokenCache, label = "store(token, validationResult)")
            reply(from = tokenCache, to = gateway, label = "cached")

            alt {
                branch(guard = "[token valid]") {
                    message(from = gateway, to = orderService, label = "GET /orders")
                    reply(from = orderService, to = gateway, label = "orderList")
                    reply(from = gateway, to = client, label = "200 OK (orderList)")
                }
                branch(guard = "[token invalid]") {
                    reply(from = gateway, to = client, label = "401 Unauthorized")
                }
            }
        }
        branch(guard = "[cache hit]") {
            reply(from = tokenCache, to = gateway, label = "validationResult")

            alt {
                branch(guard = "[token valid]") {
                    message(from = gateway, to = orderService, label = "GET /orders")
                    reply(from = orderService, to = gateway, label = "orderList")
                    reply(from = gateway, to = client, label = "200 OK (orderList)")
                }
                branch(guard = "[token invalid]") {
                    reply(from = gateway, to = client, label = "401 Unauthorized")
                }
            }
        }
    }
}

