sequenceDiagram(name = "OAuth Authorization Code Login") {
    val user = lifeline(name = "User") { isActor = true }
    val client = lifeline(name = "ClientApp")
    val authServer = lifeline(name = "AuthorizationServer")
    val sessionStore = lifeline(name = "SessionStore")
    val resourceServer = lifeline(name = "ResourceServer")
    val auditLog = lifeline(name = "AuditLog")

    message(from = user, to = client, label = "login()")
    message(from = client, to = authServer, label = "redirect: GET /authorize")
    message(from = authServer, to = sessionStore, label = "createSession()")
    reply(from = sessionStore, to = authServer, label = "sessionId")
    reply(from = authServer, to = user, label = "login form")

    message(from = user, to = authServer, label = "submit credentials")

    alt {
        branch(guard = "[credentials valid]") {
            reply(from = authServer, to = user, label = "redirect with authorization code")
            message(from = user, to = client, label = "callback(code)")
            message(from = client, to = authServer, label = "exchange code for token")
            asyncMessage(from = authServer, to = auditLog, label = "log('token issued')")
            reply(from = authServer, to = client, label = "access token")

            opt(guard = "[scope includes profile]") {
                message(from = client, to = resourceServer, label = "getUserData(token)")
                message(from = resourceServer, to = authServer, label = "verify token")
                reply(from = authServer, to = resourceServer, label = "token valid")
                reply(from = resourceServer, to = client, label = "user data")
            }
        }
        branch(guard = "[credentials invalid]") {
            message(from = authServer, to = sessionStore, label = "discardSession()")
            reply(from = authServer, to = user, label = "error message")
        }
    }
}

sequenceDiagram(name = "Order Saga - Distributed Transaction") {
    val customer = lifeline(name = "Customer") { isActor = true }
    val orderService = lifeline(name = "OrderService")
    val eventLog = lifeline(name = "EventLog")
    val warehouse = lifeline(name = "WarehouseService")
    val payment = lifeline(name = "PaymentService")
    val shipment = lifeline(name = "ShipmentService")
    val saga = lifeline(name = "SagaOrchestrator")

    message(from = customer, to = orderService, label = "placeOrder()")
    create(from = orderService, to = saga)

    message(from = saga, to = warehouse, label = "reserveItems()")
    asyncMessage(from = saga, to = eventLog, label = "log('reservation requested')")
    reply(from = warehouse, to = saga, label = "reservationStatus")

    alt {
        branch(guard = "[items available]") {
            message(from = saga, to = payment, label = "executePayment()")
            asyncMessage(from = saga, to = eventLog, label = "log('payment requested')")
            reply(from = payment, to = saga, label = "paymentStatus")

            alt {
                branch(guard = "[payment successful]") {
                    message(from = saga, to = shipment, label = "commissionShipment()")
                    asyncMessage(from = saga, to = eventLog, label = "log('shipment commissioned')")
                    reply(from = shipment, to = saga, label = "shipmentConfirmed")
                }
                branch(guard = "[payment failed]") {
                    message(from = saga, to = warehouse, label = "cancelReservation()")
                    asyncMessage(from = saga, to = eventLog, label = "log('reservation cancelled - compensation')")
                    reply(from = warehouse, to = saga, label = "cancelled")
                }
            }
        }
        branch(guard = "[items not available]") {
            asyncMessage(from = saga, to = eventLog, label = "log('order aborted - no stock')")
        }
    }

    message(from = saga, to = orderService, label = "transactionComplete(status)")
    delete(from = orderService, to = saga)
    reply(from = orderService, to = customer, label = "orderStatus")
}

