sequenceDiagram(name = "Collision Risk Assessment and Emergency Braking") {
    val camera         = lifeline(name = "CameraSensor")
    val radar          = lifeline(name = "RadarSensor")
    val fusionUnit     = lifeline(name = "FusionUnit")
    val assistant      = lifeline(name = "EmergencyBrakingAssistant")
    val driver         = lifeline(name = "Driver") { isActor = true }
    val controlUnit    = lifeline(name = "BrakeControlUnit")
    val diagnosticLog  = lifeline(name = "DiagnosticLog")

    // Sensors deliver data simultaneously, without acknowledgement
    asyncMessage(from = camera, to = fusionUnit, label = "sendMeasurementData()")
    asyncMessage(from = radar,  to = fusionUnit, label = "sendMeasurementData()")

    // internal computation of the consolidated environment model
    message(from = fusionUnit, to = fusionUnit, label = "computeConsolidatedEnvironmentModel()")

    message(from = fusionUnit, to = assistant, label = "reportCollisionRisk(timeToCollision)")

    alt {
        branch(guard = "[timeToCollision < criticalThreshold]") {
            asyncMessage(from = assistant, to = driver, label = "acousticWarning()")
            message(from = assistant, to = controlUnit, label = "initiateAutonomousBraking()")

            loop(guard = "[vehicle not stationary]") {
                message(from = assistant, to = controlUnit, label = "adjustBrakePressure()")
            }

            message(from = assistant, to = controlUnit, label = "endBrakingManeuver()")
            asyncMessage(from = assistant, to = diagnosticLog, label = "recordEvent()")
        }
        branch(guard = "[timeToCollision >= criticalThreshold]") {
            opt(guard = "[showDistanceWarning]") {
                asyncMessage(from = assistant, to = driver, label = "showDistanceWarning()")
            }
            asyncMessage(from = assistant, to = diagnosticLog, label = "logObservedRisk()")
        }
    }
}

